def transform(rows):
    seen = {}
    filtered = []
    max_n = 0.0
    for r in rows:
        trader = r.get("trader_id")
        p = float(r.get("price") or 0.0)
        q = float(r.get("qty") or 0.0)
        notional = p * q
        r["notional"] = notional
        if notional > max_n:
            max_n = notional
        if trader not in seen:
            seen[trader] = True
            filtered.append(r)
    for r in filtered:
        val = r.get("notional") or 0.0
        if val >= max_n * 0.7:
            r["status"] = "order"
        elif val >= max_n * 0.35:
            r["status"] = "during"
        else:
            r["status"] = "post"
    return filtered

output = transform(rows)
